import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.C9sp7nFj.js";const k=JSON.parse('{"title":"创建 API Key","description":"","frontmatter":{},"headers":[],"relativePath":"guide/api-key.md","filePath":"guide/api-key.md","lastUpdated":null}'),o={name:"guide/api-key.md"};function l(d,e,s,n,p,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="创建-api-key" tabindex="-1">创建 API Key <a class="header-anchor" href="#创建-api-key" aria-label="Permalink to &quot;创建 API Key&quot;">​</a></h1><p>API Key 是你调用 AI 模型的凭证，格式以 <code>sk-</code> 开头。下面介绍如何创建和管理你的 API Key。</p><h2 id="进入令牌管理" tabindex="-1">进入令牌管理 <a class="header-anchor" href="#进入令牌管理" aria-label="Permalink to &quot;进入令牌管理&quot;">​</a></h2><ol><li>登录 <a href="https://api.kkkk24juastin.asia" target="_blank" rel="noreferrer">使用站点</a></li><li>在控制台中找到并点击「令牌管理」或「API Key 管理」菜单</li></ol><h2 id="点击创建令牌" tabindex="-1">点击创建令牌 <a class="header-anchor" href="#点击创建令牌" aria-label="Permalink to &quot;点击创建令牌&quot;">​</a></h2><p>在令牌管理页面，点击「创建令牌」或「新建 API Key」按钮。</p><h2 id="设置名称、额度、模型限制" tabindex="-1">设置名称、额度、模型限制 <a class="header-anchor" href="#设置名称、额度、模型限制" aria-label="Permalink to &quot;设置名称、额度、模型限制&quot;">​</a></h2><p>创建令牌时，你需要设置以下信息：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>给这个 Key 起个名字，方便识别用途（如：ChatBox 用、开发测试用等）</td></tr><tr><td><strong>额度限制</strong>（可选）</td><td>设置这个 Key 的最大使用额度，防止意外超支</td></tr><tr><td><strong>模型限制</strong>（可选）</td><td>限制这个 Key 可以使用的模型范围</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果你是新手，建议先创建一个不限额度和模型的 Key，方便测试。后续可以根据需要创建多个 Key 分别用于不同场景。</p></div><h2 id="复制并保存-sk-开头的-key" tabindex="-1">复制并保存 sk- 开头的 Key <a class="header-anchor" href="#复制并保存-sk-开头的-key" aria-label="Permalink to &quot;复制并保存 sk- 开头的 Key&quot;">​</a></h2><p>创建成功后，页面会显示你的 API Key。你可以随时在令牌管理页面复制已创建的 Key。</p><div class="warning custom-block"><p class="custom-block-title">安全提示</p><ul><li>API Key 以 <code>sk-</code> 开头，是一串很长的字符</li><li>请勿将 API Key 分享给他人或上传到公开仓库</li></ul></div><p>复制好 API Key 后，你就可以在客户端或代码中使用它来调用 AI 模型了。</p><p>下一步：<a href="/guide/api-usage.html">API 调用方式</a></p>',15)])])}const y=a(o,[["render",l]]);export{k as __pageData,y as default};
